import os,base64,gzip,json

D1=""
D2=""

files=json.loads(gzip.decompress(base64.b64decode(D1+D2)).decode())

for p,c in files.items():
    d=os.path.dirname(p)
    if d:
        os.makedirs(d,exist_ok=True)
    open(p,"w",encoding="utf-8").write(c)
    print("wrote",p)

print("Done -",len(files),"files.")

